mapper.select:
select ss.seq , ss.remark , ss.subject , DATE_FORMAT(ss.created_at, '%Y-%m-%d %H:%i') as createdAt , DATE_FORMAT(ss.updated_at, '%Y-%m-%d %H:%i') as updatedAt , ss.deleted_at as deletedAt , ss.trashed_at AS trashedAt , ss.time_duration_ms as timeDurationMs , ss.division , IFNULL(ti.army_name,"미등록") AS armyName , ss.file_org_nm as fileOrgNm , ss.file_new_nm as fileNewNm , ss.click_least_once as clickLeastOnce , ss.reliability , IFNULL(DATE_FORMAT(ss.stt_started_at, '%Y-%m-%d %H:%i'),"") as sttStartedAt , ( select count(distinct s.seq) from tb_cs_test s LEFT JOIN tb_cs_info_user iuu ON s.tc_user_seq = iuu.seq LEFT JOIN tb_cs_info_division t ON t.division = s.division WHERE s.seq > 0 AND s.trashed_at is null
AND s.division = #{division}
AND (s.file_org_nm like CONCAT('%',#{keyword},'%'))
) as hiddenCount from tb_cs_test ss LEFT JOIN tb_cs_info_user iu ON ss.tc_user_seq = iu.seq LEFT JOIN tb_cs_info_division ti ON ti.division = ss.division WHERE ss.seq > 0 AND ss.trashed_at is null
AND ss.division = #{division}
AND (ss.file_org_nm like CONCAT('%',#{keyword},'%'))
order by ss.created_at desc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

