select seq as seq , round(start,2) as start , round(end, 2) as end , reliability , stt_text as sttText , ifnull(train_text, '') as trainText , test_seq as testSeq , created_at as createdAt , updated_at as updatedAt , use_yn as useYn , ifnull(data_id, '') as dataId ,(SELECT count(tt.test_seq) FROM tb_cs_test_trans tt WHERE tt.test_seq = #{seq}
and reliability <= #{reliability}
) AS hiddenCount from tb_cs_test_trans where test_seq = #{seq}
and reliability <= #{reliability}
order by start
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

select tr.seq as seq , te.subject , te.division , te.file_org_nm as fileOrgNm , round(tr.start, 2) as start , round(tr.end, 2) as end , tr.reliability , tr.stt_text as sttText , trim(IF(tr.train_text IS NULL or tr.train_text = '', tr.stt_text, tr.train_text)) as trainText , tr.test_seq as testSeq , tr.created_at as createdAt , DATE_FORMAT(tr.updated_at, '%Y-%m-%d %H:%i') as updatedAt , if ( te.trashed_at IS NOT NULL, 'N', if(te.deleted_at IS NOT NULL, 'N', tr.use_yn)) AS useYn , ifnull(tr.data_id, '') as dataId , ifnull(te.file_new_nm, '') as fileNewNm , pr.data_id AS prDataId , pr.seq AS prSeq , ifnull(pr.train_text, '') AS prTrainText , trim(ifnull(pr.use_yn, '')) AS prUseYn , IF ( tr.seq != pr.seq OR trim(IF(tr.train_text IS NULL or tr.train_text = '', tr.stt_text, tr.train_text)) != ifnull(pr.train_text, '') OR tr.use_yn != trim(ifnull(pr.use_yn, '')) OR round(tr.start,2) != round(pr.start,2) OR round(tr.end,2) != round(pr.end,2) ,'Y', 'N' ) AS candidate , ( select count(tra.seq) from tb_cs_test_trans tra join tb_cs_test tea on tea.seq != -1 and tra.test_seq = tea.seq LEFT JOIN tb_cs_test_trans_pair pra ON pra.data_id != '' AND tra.data_id = pra.data_id where tra.test_seq != -1 AND ( ( tra.data_id = '' AND tra.use_yn = 'Y' ) or ( tra.data_id != '' AND IF ( tra.seq != pra.seq OR trim(IF(tra.train_text IS NULL or tra.train_text = '', tra.stt_text, tra.train_text)) != ifnull(pra.train_text, '') OR tra.use_yn != trim(ifnull(pra.use_yn, '')) OR round(tra.start,2) != round(pra.start,2) OR round(tra.end,2) != round(pra.end,2) ,'Y', 'N' ) = 'Y' ) )
AND tra.use_yn = #{useYn}
AND tea.division = #{search.searchDivision}
) as hiddenCount from tb_cs_test_trans tr JOIN tb_cs_test te on te.seq != -1 and tr.test_seq = te.seq LEFT JOIN tb_cs_test_trans_pair pr ON pr.data_id != '' AND tr.data_id = pr.data_id where tr.test_seq != -1 AND ( ( tr.data_id = '' AND tr.use_yn = 'Y' ) or ( tr.data_id != '' AND IF ( tr.seq != pr.seq OR trim(IF(tr.train_text IS NULL or tr.train_text = '', tr.stt_text, tr.train_text)) != ifnull(pr.train_text, '') OR tr.use_yn != trim(ifnull(pr.use_yn, '')) OR round(tr.start,2) != round(pr.start,2) OR round(tr.end,2) != round(pr.end,2) ,'Y', 'N' ) = 'Y' ) )
AND tr.use_yn = #{useYn}
AND te.division = #{search.searchDivision}
order BY te.file_org_nm DESC, tr.start asc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

