mapper.select:
select ss.seq , ss.remark , ss.subject , ss.created_at as createdAt , ss.updated_at as updatedAt , ss.deleted_at as deletedAt , ss.trashed_at AS trashedAt , ss.time_duration_ms as timeDurationMs , ss.division , ss.file_org_nm as fileOrgNm , ss.file_new_nm as fileNewNm , ss.click_least_once as clickLeastOnce , ss.reliability , ss.stt_started_at as sttStartedAt , ( select count(distinct s.seq) from tb_cs_test s LEFT JOIN tb_cs_info_user iuu ON s.tc_user_seq = iuu.seq WHERE s.seq > 0 AND s.trashed_at is null AND s.created_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND (s.file_org_nm like CONCAT('%',#{search.searchText},'%'))
) as hiddenCount from tb_cs_test ss LEFT JOIN tb_cs_info_user iu ON ss.tc_user_seq = iu.seq WHERE ss.seq > 0 AND ss.trashed_at is null AND ss.created_at BETWEEN DATE(#{search.searchStartDate}) AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND (ss.file_org_nm like CONCAT('%',#{search.searchText},'%'))
order by ss.created_at desc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

select seq , channel_id as channelId , CASE WHEN channel_id = 0 THEN 'L' ELSE 'R' END AS channelChar , round(start,2) as start , round(end,2) as end , reliability , stt_text as sttText , train_text as trainText ,data_id AS dataId , ( SELECT count(ct.seq) from tb_cs_test_trans ct where test_seq = #{meetSeq}
and reliability <= #{reliability}
and train_text is not null and train_text != ''
) AS hiddenCount from tb_cs_test_trans where test_seq = #{meetSeq}
and train_text IS NOT NULL and train_text != ''
and reliability <= #{reliability}
order by channel_id, start
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

select tr.seq as seq , te.subject , te.division , te.file_org_nm as fileOrgNm , round(tr.start, 2) as start , round(tr.end, 2) as end , tr.reliability , tr.stt_text as sttText , trim(IF(tr.train_text IS NULL or tr.train_text = '', tr.stt_text, tr.train_text)) as trainText , tr.test_seq as testSeq , DATE_FORMAT(tr.created_at, '%Y-%m-%d') as createdAt , DATE_FORMAT(tr.updated_at, '%Y-%m-%d %H:%i') as updatedAt , if ( te.trashed_at IS NOT NULL, 'N', if(te.deleted_at IS NOT NULL, 'N', tr.use_yn)) AS useYn , ifnull(tr.data_id, '') as dataId , ifnull(te.file_new_nm, '') as fileNewNm , pr.data_id AS prDataId , pr.seq AS prSeq , ifnull(pr.train_text, '') AS prTrainText , trim(ifnull(pr.use_yn, '')) AS prUseYn , IF ( tr.seq != pr.seq OR trim(IF(tr.train_text IS NULL or tr.train_text = '', tr.stt_text, tr.train_text)) != ifnull(pr.train_text, '') OR tr.use_yn != trim(ifnull(pr.use_yn, '')) OR round(tr.start,2) != round(pr.start,2) OR round(tr.end,2) != round(pr.end,2) ,'Y', 'N' ) AS candidate , ( select count(tra.seq) from tb_cs_test_trans tra join tb_cs_test tea on tea.seq != -1 and tra.test_seq = tea.seq LEFT JOIN tb_cs_test_trans_pair pra ON pra.data_id != '' AND tra.data_id = pra.data_id where tra.test_seq != -1
AND tra.created_at BETWEEN str_to_date(#{search.searchStartDate}, '%Y-%m-%d') AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND tra.use_yn = #{search.searchUseYn}
AND tea.division = #{search.searchDivision}
AND ( IF(tra.train_text IS NULL or tra.train_text = '', tra.stt_text, tra.train_text) LIKE concat('%', #{search.searchText}, '%') OR tea.file_org_nm LIKE concat('%', #{search.searchText}, '%') )
) as hiddenCount from tb_cs_test_trans tr JOIN tb_cs_test te on te.seq != -1 and tr.test_seq = te.seq LEFT JOIN tb_cs_test_trans_pair pr ON pr.data_id != '' AND tr.data_id = pr.data_id where tr.test_seq != -1
AND tr.created_at BETWEEN str_to_date(#{search.searchStartDate}, '%Y-%m-%d') AND DATE_ADD(#{search.searchEndDate}, INTERVAL 1 DAY )
AND tr.use_yn = #{search.searchUseYn}
AND te.division = #{search.searchDivision}
AND ( IF(tr.train_text IS NULL or tr.train_text = '', tr.stt_text, tr.train_text) LIKE concat('%', #{search.searchText}, '%') OR te.file_org_nm LIKE concat('%', #{search.searchText}, '%') )
order BY te.created_at DESC, tr.start asc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

select ss.seq , ss.division , IFNULL(ti.army_name,"미등록") AS armyName , DATE_FORMAT(ss.created_at, '%Y-%m-%d %H:%i') as createdAt , DATE_FORMAT(ss.updated_at, '%Y-%m-%d %H:%i') as updatedAt , ss.file_org_nm as fileOrgNm , IFNULL(DATE_FORMAT(ss.stt_started_at, '%Y-%m-%d %H:%i'),"") as sttStartedAt , ss.status , IFNULL(ss.error_message,"")as errorMessage , ( select count(distinct s.seq) from tb_cs_test s LEFT JOIN tb_cs_info_division t ON t.division = s.division WHERE (s.status < 20 OR s.status = 10 and s.error_message IS NOT NULL)
AND s.division = #{division}
AND (s.file_org_nm like CONCAT('%',#{keyword},'%'))
) as hiddenCount from tb_cs_test ss LEFT JOIN tb_cs_info_division ti ON ti.division = ss.division WHERE (ss.status < 20 OR ss.status = 10 and ss.error_message IS NOT NULL) and ss.seq != -1
AND ss.division = #{division}
AND (ss.file_org_nm like CONCAT('%',#{keyword},'%'))
order by ss.created_at desc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}
